// InvestigationLogs.jsx
// Single React component that renders the "Investigation Logs" page content.
// NOTE: This is page content only. Do NOT include header/sidebar/footer here.
// Wrap this component in your existing <TechnicianLayout> where you mount pages.
//
// Tech stack: React + Tailwind CSS
// Dummy data included below. Replace data fetching with backend API calls as noted.
//
// Backend API mapping (examples):
//  - GET /api/investigations?search=&status=&severity=&from=&to=&sortField=&sortDir=
//      -> returns list of investigation summary objects
//  - GET /api/investigations/:caseId/timeline
//      -> returns timeline entries for the case
//  - GET /api/investigations/:caseId/evidence
//      -> returns evidence list for the case
//  - POST /api/audit/log (for logging UI actions like 'viewed timeline')
// Replace local dummy filtering with server-side filtering & pagination for enterprise scale.

import React, { useState, useMemo, useEffect } from "react";

/* ------------------------------
   Dummy JSON data (replace with API)
   ------------------------------ */
const DUMMY_INVESTIGATIONS = [
  {
    caseId: "CASE-2026-0001",
    systemId: "SYS-1001",
    technician: "Priya Sharma",
    initialAIVerdict: { label: "Potential Compromise", confidence: 0.78 },
    finalTechnicianVerdict: "Confirmed - Malware",
    evidenceCount: 3,
    status: "Closed", // Open, In Progress, Escalated, Closed
    severity: "High", // Low, Medium, High, Critical
    lastUpdated: "2026-01-16T14:32:00Z",
    timeline: [
      { ts: "2026-01-15T10:05:00Z", actor: "AI Engine", type: "AI_VERDICT", note: "Low confidence alert detected (0.78)" },
      { ts: "2026-01-15T10:12:00Z", actor: "System", type: "TECH_ASSIGNED", note: "Technician Priya assigned" },
      { ts: "2026-01-15T11:04:00Z", actor: "Priya Sharma", type: "NOTE", note: "Observed suspicious binaries in %TEMP%" },
      { ts: "2026-01-15T11:20:00Z", actor: "Priya Sharma", type: "EVIDENCE_UPLOADED", note: "malware_sample.exe (hash: abc123)" },
      { ts: "2026-01-16T09:00:00Z", actor: "Priya Sharma", type: "VERDICT_CHANGE", note: "Marked as Confirmed - Malware" },
      { ts: "2026-01-16T14:30:00Z", actor: "Priya Sharma", type: "CLOSE", note: "Remediation completed and case closed" }
    ],
    evidence: [
      { filename: "malware_sample.exe", type: "binary", uploadedBy: "Priya Sharma", ts: "2026-01-15T11:20:00Z", retained: true },
      { filename: "proc_snapshot.json", type: "json", uploadedBy: "Priya Sharma", ts: "2026-01-15T11:05:00Z", retained: true },
      { filename: "syslog_excerpt.log", type: "log", uploadedBy: "Priya Sharma", ts: "2026-01-15T10:45:00Z", retained: false }
    ],
    compliance: { evidenceRetained: true, notesPresent: true, aiConfidenceLogged: true, adminNotified: true }
  },
  {
    caseId: "CASE-2026-0002",
    systemId: "SYS-2003",
    technician: "Amit Verma",
    initialAIVerdict: { label: "False Positive", confidence: 0.20 },
    finalTechnicianVerdict: "False Positive - No Action",
    evidenceCount: 0,
    status: "Closed",
    severity: "Low",
    lastUpdated: "2026-01-10T09:12:00Z",
    timeline: [
      { ts: "2026-01-09T08:00:00Z", actor: "AI Engine", type: "AI_VERDICT", note: "Low confidence: benign" },
      { ts: "2026-01-09T08:30:00Z", actor: "System", type: "TECH_ASSIGNED", note: "Technician Amit assigned" },
      { ts: "2026-01-09T09:10:00Z", actor: "Amit Verma", type: "NOTE", note: "Event matched pattern for scheduled job; closing." },
      { ts: "2026-01-10T09:05:00Z", actor: "System", type: "CLOSE", note: "Closed (no action required)" }
    ],
    evidence: [],
    compliance: { evidenceRetained: false, notesPresent: true, aiConfidenceLogged: true, adminNotified: false }
  },
  {
    caseId: "CASE-2026-0003",
    systemId: "SYS-4010",
    technician: "Raghav Das",
    initialAIVerdict: { label: "Suspicious - Lateral Movement", confidence: 0.92 },
    finalTechnicianVerdict: "Escalated",
    evidenceCount: 7,
    status: "Escalated",
    severity: "Critical",
    lastUpdated: "2026-01-20T19:00:00Z",
    timeline: [
      { ts: "2026-01-20T12:01:00Z", actor: "AI Engine", type: "AI_VERDICT", note: "High confidence lateral movement detected (0.92)" },
      { ts: "2026-01-20T12:10:00Z", actor: "System", type: "TECH_ASSIGNED", note: "Technician Raghav assigned" },
      { ts: "2026-01-20T12:22:00Z", actor: "Raghav Das", type: "NOTE", note: "Found multiple lateral connections from 10.0.3.5" },
      { ts: "2026-01-20T12:30:00Z", actor: "Raghav Das", type: "EVIDENCE_UPLOADED", note: "pcap_capture.pcap" },
      { ts: "2026-01-20T13:05:00Z", actor: "Raghav Das", type: "ESCALATION", note: "Escalated to Incident Response Team" }
    ],
    evidence: [
      { filename: "pcap_capture.pcap", type: "pcap", uploadedBy: "Raghav Das", ts: "2026-01-20T12:30:00Z", retained: true },
      { filename: "netstat.txt", type: "text", uploadedBy: "Raghav Das", ts: "2026-01-20T12:25:00Z", retained: true },
      // ... more items
    ],
    compliance: { evidenceRetained: true, notesPresent: true, aiConfidenceLogged: true, adminNotified: true }
  }
];

/* ------------------------------
   Helpers: formatters & UI helpers
   ------------------------------ */
const formatDateTime = (iso) => {
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  return d.toLocaleString(); // Use user's locale (enterprise may require server-side timezone)
};

const statusColor = (status) => {
  switch (status) {
    case "Open":
      return "bg-yellow-100 text-yellow-800";
    case "In Progress":
      return "bg-blue-100 text-blue-800";
    case "Escalated":
      return "bg-red-100 text-red-800";
    case "Closed":
      return "bg-green-100 text-green-800";
    default:
      return "bg-gray-100 text-gray-800";
  }
};

const severityColor = (sev) => {
  switch (sev) {
    case "Low":
      return "text-green-600";
    case "Medium":
      return "text-yellow-600";
    case "High":
      return "text-orange-700";
    case "Critical":
      return "text-red-700";
    default:
      return "text-gray-700";
  }
};

const verdictBadge = (label) => {
  // High level mapping for AI/Technician verdict chips
  const lower = label?.toLowerCase?.() || "";
  if (lower.includes("malware") || lower.includes("confirmed") || lower.includes("compromise") || lower.includes("suspicious")) {
    return "bg-red-50 text-red-700 border border-red-200";
  }
  if (lower.includes("false") || lower.includes("benign") || lower.includes("no action")) {
    return "bg-green-50 text-green-700 border border-green-200";
  }
  return "bg-gray-50 text-gray-700 border border-gray-200";
};

/* ------------------------------
   Main Component
   ------------------------------ */
export default function InvestigationLogs() {
  // Data - in production, replace this state with API response (useEffect fetch).
  const [investigations, setInvestigations] = useState(DUMMY_INVESTIGATIONS);

  // UI state
  const [search, setSearch] = useState("");
  const [filterPanelOpen, setFilterPanelOpen] = useState(false);
  const [statusFilter, setStatusFilter] = useState(""); // e.g., "Open", "Closed", etc.
  const [severityFilter, setSeverityFilter] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");

  const [sortField, setSortField] = useState("lastUpdated");
  const [sortDir, setSortDir] = useState("desc"); // asc | desc

  // Drawer state for Timeline/Evidence
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [activeCase, setActiveCase] = useState(null);

  // Pagination (simple, in-memory)
  const [page, setPage] = useState(1);
  const PAGE_SIZE = 10;

  // Derived filtered & sorted list
  const filteredInvestigations = useMemo(() => {
    const q = search.trim().toLowerCase();
    let list = investigations.filter((inv) => {
      // Search across systemId and technician
      const matchSearch =
        !q ||
        inv.systemId.toLowerCase().includes(q) ||
        inv.technician.toLowerCase().includes(q) ||
        inv.caseId.toLowerCase().includes(q);

      const matchStatus = !statusFilter || inv.status === statusFilter;
      const matchSeverity = !severityFilter || inv.severity === severityFilter;

      const matchDate =
        (!dateFrom || new Date(inv.lastUpdated) >= new Date(dateFrom)) &&
        (!dateTo || new Date(inv.lastUpdated) <= new Date(dateTo + "T23:59:59"));

      return matchSearch && matchStatus && matchSeverity && matchDate;
    });

    // Sorting
    list.sort((a, b) => {
      let av = a[sortField];
      let bv = b[sortField];

      // support nested fields
      if (sortField === "lastUpdated") {
        av = new Date(a.lastUpdated).getTime();
        bv = new Date(b.lastUpdated).getTime();
      }
      if (sortField === "evidenceCount" || sortField === "severity") {
        // evidenceCount numeric
      }

      if (av === bv) return 0;
      if (sortDir === "asc") return av > bv ? 1 : -1;
      return av > bv ? -1 : 1;
    });

    return list;
  }, [investigations, search, statusFilter, severityFilter, dateFrom, dateTo, sortField, sortDir]);

  // Page items
  const totalPages = Math.max(1, Math.ceil(filteredInvestigations.length / PAGE_SIZE));
  const pageItems = filteredInvestigations.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  useEffect(() => {
    // Reset page if filter/search changes
    setPage(1);
  }, [search, statusFilter, severityFilter, dateFrom, dateTo]);

  // Sorting handler
  const toggleSort = (field) => {
    if (sortField === field) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortField(field);
      setSortDir("asc");
    }
  };

  // Open drawer for selected case
  const openTimeline = (caseItem) => {
    setActiveCase(caseItem);

    // In production: Fetch timeline + evidence from API:
    // fetch(`/api/investigations/${caseItem.caseId}/timeline`).then(...)
    // fetch(`/api/investigations/${caseItem.caseId}/evidence`).then(...)
    setDrawerOpen(true);

    // Optionally: Log audit event to server
    // fetch('/api/audit/log', {method:'POST', body: JSON.stringify({action:'view_timeline', caseId: caseItem.caseId, actor: 'current_user'})})
  };

  // Close drawer
  const closeDrawer = () => {
    setDrawerOpen(false);
    setActiveCase(null);
  };

  return (
    <div className="w-full h-full">
      {/* Page header */}
      <div className="mb-6 flex items-start justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900">Investigation Logs</h1>
          <p className="mt-1 text-sm text-gray-600">Technician investigation history and audit trail</p>
        </div>

        {/* Right controls: Search + Filter */}
        <div className="flex items-center gap-3">
          <div className="relative">
            <input
              aria-label="Search by System ID or Technician"
              placeholder="Search (System ID / Technician / Case ID)"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-80 pl-10 pr-4 py-2 border rounded-md shadow-sm text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <svg className="w-4 h-4 absolute left-3 top-2.5 text-gray-400 pointer-events-none" viewBox="0 0 24 24" fill="none">
              <path d="M21 21l-4.35-4.35" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
              <circle cx="11" cy="11" r="6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </div>

          <div className="relative">
            <button
              onClick={() => setFilterPanelOpen((v) => !v)}
              className="flex items-center gap-2 px-3 py-2 bg-white border rounded-md shadow-sm text-sm hover:bg-gray-50"
            >
              <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none">
                <path d="M4 6h16M10 12h4M6 18h12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              Filters
            </button>

            {/* Filter popover */}
            {filterPanelOpen && (
              <div className="absolute right-0 mt-2 w-80 bg-white border rounded-md shadow-lg p-4 z-30">
                <div className="space-y-3">
                  <div>
                    <label className="block text-xs text-gray-500">Status</label>
                    <select
                      value={statusFilter}
                      onChange={(e) => setStatusFilter(e.target.value)}
                      className="mt-1 block w-full py-1.5 border rounded-md text-sm"
                    >
                      <option value="">All</option>
                      <option>Open</option>
                      <option>In Progress</option>
                      <option>Escalated</option>
                      <option>Closed</option>
                    </select>
                  </div>

                  <div>
                    <label className="block text-xs text-gray-500">Severity</label>
                    <select
                      value={severityFilter}
                      onChange={(e) => setSeverityFilter(e.target.value)}
                      className="mt-1 block w-full py-1.5 border rounded-md text-sm"
                    >
                      <option value="">All</option>
                      <option>Low</option>
                      <option>Medium</option>
                      <option>High</option>
                      <option>Critical</option>
                    </select>
                  </div>

                  <div>
                    <label className="block text-xs text-gray-500">From (Last Updated)</label>
                    <input type="date" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} className="mt-1 block w-full py-1.5 border rounded-md text-sm" />
                  </div>

                  <div>
                    <label className="block text-xs text-gray-500">To (Last Updated)</label>
                    <input type="date" value={dateTo} onChange={(e) => setDateTo(e.target.value)} className="mt-1 block w-full py-1.5 border rounded-md text-sm" />
                  </div>

                  <div className="flex justify-between items-center pt-2">
                    <button
                      onClick={() => {
                        setStatusFilter("");
                        setSeverityFilter("");
                        setDateFrom("");
                        setDateTo("");
                      }}
                      className="text-sm text-gray-600 hover:underline"
                    >
                      Clear
                    </button>
                    <button
                      onClick={() => setFilterPanelOpen(false)}
                      className="px-3 py-1.5 bg-blue-600 text-white rounded-md text-sm"
                    >
                      Apply
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Investigation table */}
      <div className="bg-white border rounded-lg shadow-sm">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky top-0">
              <tr>
                <th
                  onClick={() => toggleSort("caseId")}
                  className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    Case ID
                    {sortField === "caseId" && <SortIndicator dir={sortDir} />}
                  </div>
                </th>

                <th
                  onClick={() => toggleSort("systemId")}
                  className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    System ID
                    {sortField === "systemId" && <SortIndicator dir={sortDir} />}
                  </div>
                </th>

                <th
                  onClick={() => toggleSort("technician")}
                  className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    Technician
                    {sortField === "technician" && <SortIndicator dir={sortDir} />}
                  </div>
                </th>

                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Initial AI Verdict</th>

                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Final Technician Verdict</th>

                <th
                  onClick={() => toggleSort("evidenceCount")}
                  className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    Evidence Count
                    {sortField === "evidenceCount" && <SortIndicator dir={sortDir} />}
                  </div>
                </th>

                <th
                  onClick={() => toggleSort("status")}
                  className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    Investigation Status
                    {sortField === "status" && <SortIndicator dir={sortDir} />}
                  </div>
                </th>

                <th
                  onClick={() => toggleSort("lastUpdated")}
                  className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer"
                >
                  <div className="flex items-center gap-2">
                    Last Updated
                    {sortField === "lastUpdated" && <SortIndicator dir={sortDir} />}
                  </div>
                </th>

                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Action</th>
              </tr>
            </thead>

            <tbody className="bg-white divide-y divide-gray-200">
              {pageItems.length === 0 ? (
                <tr>
                  <td colSpan="9" className="px-4 py-6 text-center text-sm text-gray-500">
                    No investigations found
                  </td>
                </tr>
              ) : (
                pageItems.map((inv) => (
                  <tr key={inv.caseId} className="hover:bg-gray-50">
                    <td className="px-4 py-3 whitespace-nowrap text-sm font-medium text-gray-900">{inv.caseId}</td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm text-blue-600 hover:underline cursor-pointer" onClick={() => console.log("Open system details:", inv.systemId)}>
                      {inv.systemId}
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-700">{inv.technician}</td>

                    <td className="px-4 py-3 whitespace-nowrap">
                      <div className={`inline-flex items-center px-2 py-0.5 text-sm rounded ${verdictBadge(inv.initialAIVerdict?.label)}`}>
                        <span className="font-medium mr-2">{inv.initialAIVerdict?.label}</span>
                        <span className="text-xs text-gray-500">({Math.round((inv.initialAIVerdict?.confidence ?? 0) * 100)}%)</span>
                      </div>
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm">
                      <div className={`inline-flex items-center px-2 py-0.5 text-sm rounded ${verdictBadge(inv.finalTechnicianVerdict)}`}>
                        {inv.finalTechnicianVerdict}
                      </div>
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-700">{inv.evidenceCount}</td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm">
                      <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${statusColor(inv.status)}`}>
                        {inv.status}
                      </span>
                      <div className={`mt-1 text-xs ${severityColor(inv.severity)}`}>{inv.severity}</div>
                    </td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-500">{formatDateTime(inv.lastUpdated)}</td>

                    <td className="px-4 py-3 whitespace-nowrap text-sm">
                      <button
                        onClick={() => openTimeline(inv)}
                        className="px-3 py-1.5 bg-white border rounded-md text-sm hover:bg-gray-50"
                      >
                        View Timeline
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination footer */}
        <div className="px-4 py-3 bg-gray-50 flex items-center justify-between border-t">
          <div className="text-sm text-gray-600">Showing {filteredInvestigations.length === 0 ? 0 : (page - 1) * PAGE_SIZE + 1} - {Math.min(page * PAGE_SIZE, filteredInvestigations.length)} of {filteredInvestigations.length}</div>
          <div className="flex items-center gap-2">
            <button onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={page === 1} className={`px-2 py-1 rounded ${page === 1 ? "text-gray-400" : "bg-white border"}`}>
              Prev
            </button>
            <div className="px-3 py-1 border rounded text-sm bg-white">{page} / {totalPages}</div>
            <button onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={page === totalPages} className={`px-2 py-1 rounded ${page === totalPages ? "text-gray-400" : "bg-white border"}`}>
              Next
            </button>
          </div>
        </div>
      </div>

      {/* Drawer: Timeline + Evidence + Compliance */}
      {drawerOpen && activeCase && (
        <div className="fixed inset-0 z-50 flex">
          {/* overlay */}
          <div className="absolute inset-0 bg-black opacity-40" onClick={closeDrawer} />

          {/* drawer panel */}
          <div className="relative ml-auto w-full max-w-3xl bg-white h-full shadow-2xl overflow-auto">
            <div className="p-4 border-b flex items-start justify-between gap-4">
              <div>
                <h2 className="text-lg font-semibold text-gray-900">Timeline - {activeCase.caseId}</h2>
                <p className="text-sm text-gray-600">System: {activeCase.systemId} · Technician: {activeCase.technician}</p>
              </div>
              <div className="flex items-center gap-3">
                {/* Compliance indicators */}
                <div className="flex items-center gap-2">
                  <ComplianceBadge label="Evidence retained" active={activeCase.compliance?.evidenceRetained} />
                  <ComplianceBadge label="Notes present" active={activeCase.compliance?.notesPresent} />
                  <ComplianceBadge label="AI confidence" active={activeCase.compliance?.aiConfidenceLogged} />
                  <ComplianceBadge label="Admin notified" active={activeCase.compliance?.adminNotified} />
                </div>

                <button onClick={closeDrawer} className="p-2 rounded hover:bg-gray-100">
                  <svg className="w-5 h-5 text-gray-600" viewBox="0 0 24 24" fill="none">
                    <path d="M6 18L18 6M6 6l12 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                </button>
              </div>
            </div>

            <div className="p-6 space-y-6">
              {/* Timeline section */}
              <section>
                <h3 className="text-sm font-medium text-gray-700 mb-3">Investigation Timeline</h3>
                <div className="border rounded-md divide-y">
                  {activeCase.timeline && activeCase.timeline.length > 0 ? (
                    activeCase.timeline.map((entry, idx) => (
                      <div key={idx} className="p-4 flex gap-4">
                        <div className="flex-shrink-0">
                          <IconForType type={entry.type} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center justify-between">
                            <div className="text-sm font-semibold text-gray-800">{entry.type.replace(/_/g, " ")}</div>
                            <div className="text-xs text-gray-500">{formatDateTime(entry.ts)}</div>
                          </div>
                          <div className="text-sm text-gray-600">{entry.note}</div>
                          <div className="mt-1 text-xs text-gray-500">By: {entry.actor}</div>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="p-4 text-sm text-gray-500">No timeline entries available.</div>
                  )}
                </div>
              </section>

              {/* Evidence summary */}
              <section>
                <h3 className="text-sm font-medium text-gray-700 mb-3">Evidence Summary ({activeCase.evidence?.length || 0})</h3>
                <div className="border rounded-md">
                  {activeCase.evidence && activeCase.evidence.length > 0 ? (
                    <table className="min-w-full divide-y">
                      <thead className="bg-gray-50">
                        <tr>
                          <th className="px-4 py-2 text-left text-xs text-gray-500">File Name</th>
                          <th className="px-4 py-2 text-left text-xs text-gray-500">Type</th>
                          <th className="px-4 py-2 text-left text-xs text-gray-500">Uploaded By</th>
                          <th className="px-4 py-2 text-left text-xs text-gray-500">Timestamp</th>
                          <th className="px-4 py-2 text-left text-xs text-gray-500">Retained</th>
                        </tr>
                      </thead>
                      <tbody className="bg-white divide-y">
                        {activeCase.evidence.map((ev, i) => (
                          <tr key={i}>
                            <td className="px-4 py-2 text-sm text-blue-600 hover:underline cursor-pointer" onClick={() => console.log("Download requested for:", ev.filename)}>
                              {ev.filename}
                            </td>
                            <td className="px-4 py-2 text-sm">{ev.type}</td>
                            <td className="px-4 py-2 text-sm">{ev.uploadedBy}</td>
                            <td className="px-4 py-2 text-sm text-gray-500">{formatDateTime(ev.ts)}</td>
                            <td className="px-4 py-2 text-sm">
                              {ev.retained ? <span className="text-green-600 font-medium">Yes</span> : <span className="text-gray-500">No</span>}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  ) : (
                    <div className="p-4 text-sm text-gray-500">No evidence uploaded for this case.</div>
                  )}
                </div>
              </section>

              {/* Audit actions */}
              <section>
                <h3 className="text-sm font-medium text-gray-700 mb-3">Audit Actions</h3>
                <div className="flex gap-2">
                  <button
                    onClick={() => {
                      // Example action: Mark retention flag (in production call API)
                      alert(`Audit: Marked evidence retention for ${activeCase.caseId}`);
                    }}
                    className="px-3 py-1.5 bg-white border rounded-md text-sm hover:bg-gray-50"
                  >
                    Mark Evidence Retained
                  </button>

                  <button
                    onClick={() => {
                      // Example action: export timeline as PDF/JSON (placeholder)
                      alert(`Audit: Export timeline for ${activeCase.caseId} (JSON)`);
                    }}
                    className="px-3 py-1.5 bg-white border rounded-md text-sm hover:bg-gray-50"
                  >
                    Export Timeline (JSON)
                  </button>
                </div>
              </section>

              {/* Raw metadata / quick notes for auditors */}
              <section>
                <h3 className="text-sm font-medium text-gray-700 mb-3">Compliance & Metadata</h3>
                <div className="bg-gray-50 p-3 rounded-md text-sm text-gray-700">
                  <div><strong>Case ID:</strong> {activeCase.caseId}</div>
                  <div><strong>System ID:</strong> {activeCase.systemId}</div>
                  <div><strong>Last Updated:</strong> {formatDateTime(activeCase.lastUpdated)}</div>
                  <div><strong>Severity:</strong> <span className={severityColor(activeCase.severity)}>{activeCase.severity}</span></div>
                </div>
              </section>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ------------------------------
   Small subcomponents used above
   ------------------------------ */

function SortIndicator({ dir }) {
  return (
    <svg className="w-3 h-3 text-gray-400" viewBox="0 0 24 24" fill="none">
      {dir === "asc" ? (
        <path d="M6 15l6-6 6 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
      ) : (
        <path d="M6 9l6 6 6-6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
      )}
    </svg>
  );
}

function ComplianceBadge({ label, active }) {
  return (
    <div className={`inline-flex items-center gap-2 px-2 py-1 rounded-md text-xs ${active ? "bg-green-50 text-green-800 border border-green-100" : "bg-gray-50 text-gray-600 border border-gray-100"}`}>
      <svg className={`w-3 h-3 ${active ? "text-green-600" : "text-gray-400"}`} viewBox="0 0 24 24" fill="none">
        {active ? (
          <path d="M5 13l4 4L19 7" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
        ) : (
          <circle cx="12" cy="12" r="9" stroke="currentColor" strokeWidth="1.5" />
        )}
      </svg>
      <span>{label}</span>
    </div>
  );
}

function IconForType({ type }) {
  // Map entry types to lightweight icons
  switch (type) {
    case "AI_VERDICT":
      return (
        <div className="w-9 h-9 rounded-full bg-indigo-50 flex items-center justify-center">
          <svg className="w-5 h-5 text-indigo-600" viewBox="0 0 24 24" fill="none">
            <path d="M3 12h18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
            <path d="M12 3v18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
          </svg>
        </div>
      );
    case "TECH_ASSIGNED":
      return (
        <div className="w-9 h-9 rounded-full bg-blue-50 flex items-center justify-center">
          <svg className="w-5 h-5 text-blue-600" viewBox="0 0 24 24" fill="none">
            <path d="M12 12a5 5 0 100-10 5 5 0 000 10z" stroke="currentColor" strokeWidth="1.5" />
            <path d="M21 21a9 9 0 10-18 0" stroke="currentColor" strokeWidth="1.5" />
          </svg>
        </div>
      );
    case "EVIDENCE_UPLOADED":
    case "ESCALATION":
      return (
        <div className="w-9 h-9 rounded-full bg-red-50 flex items-center justify-center">
          <svg className="w-5 h-5 text-red-600" viewBox="0 0 24 24" fill="none">
            <path d="M12 2l3 7h7l-5.5 4.2L19 22l-7-4-7 4 1.5-8.8L2 9h7z" stroke="currentColor" strokeWidth="0.5" />
          </svg>
        </div>
      );
    default:
      return (
        <div className="w-9 h-9 rounded-full bg-gray-50 flex items-center justify-center">
          <svg className="w-5 h-5 text-gray-500" viewBox="0 0 24 24" fill="none">
            <circle cx="12" cy="12" r="9" stroke="currentColor" strokeWidth="1.5" />
          </svg>
        </div>
      );
  }
}
